SCHEMA = {
    "name": "silent_block_efficiency_analyzer",
    "description": "Calculates the Dexterity-adjusted block values for Silent's block cards in hand, returning them sorted by block-per-energy efficiency. Use this to decide WHICH block cards to play when facing incoming damage.",
    "input_schema": {
        "type": "object",
        "properties": {
            "hand": {
                "type": "array",
                "description": "List of card names in hand (e.g. ['Defend', 'Survivor+'])"
            },
            "dexterity": {
                "type": "integer",
                "description": "Current Dexterity. Defaults to 0."
            },
            "energy": {
                "type": "integer",
                "description": "Current Energy available."
            }
        },
        "required": ["hand", "dexterity", "energy"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(hand, dexterity, energy):
    dex = int(dexterity) if dexterity is not None else 0
    eng = int(energy) if energy is not None else 0
    if not hand:
        return {"analyzed_cards": [], "best_efficiency": None, "playable_block_sum": 0}

    block_bases = {
        "Defend": (1, 5, 8),
        "Survivor": (1, 8, 11),
        "Backflip": (1, 5, 8),
        "Dodge and Roll": (1, 4, 6),
        "Cloak and Dagger": (1, 6, 6),
        "Leg Sweep": (2, 11, 14),
        "Dash": (2, 10, 13),
        "Deflect": (0, 4, 7),
        "Escape Plan": (0, 3, 5),
        "Blur": (1, 5, 8)
    }

    results = []
    for card in hand:
        if isinstance(card, dict):
            name = card.get("name", "")
        else:
            name = str(card)

        base_name = name.replace("+", "")
        if base_name in block_bases:
            cost, base_block, upg_block = block_bases[base_name]
            is_upgraded = "+" in name
            actual_base = upg_block if is_upgraded else base_block

            actual_block = max(0, actual_base + dex)

            efficiency = actual_block / cost if cost > 0 else actual_block * 2.0

            results.append({
                "card": name,
                "cost": cost,
                "block_yield": actual_block,
                "block_per_energy": round(efficiency, 2),
                "playable": eng >= cost
            })

    results.sort(key=lambda x: x["block_per_energy"], reverse=True)

    return {
        "analyzed_cards": results,
        "best_efficiency": results[0]["card"] if results else None,
        "playable_block_sum": sum(r["block_yield"] for r in results if r["playable"])
    }

