SCHEMA = {
    "name": "poison_math_calculator",
    "description": "Calculates exactly how much total damage current poison stacks will do over time, how many turns until lethal, and whether lethal is achieved this turn.",
    "input_schema": {
        "type": "object",
        "properties": {
            "poison_stacks": {
                "description": "Current poison stacks. Can be an integer or a list."
            },
            "enemy_hp": {
                "description": "Current enemy HP. Can be an integer or a list."
            }
        },
        "required": ["poison_stacks", "enemy_hp"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(poison_stacks=0, enemy_hp=0):
    def _get_first(val):
        if isinstance(val, list):
            return val[0] if val else 0
        return val if val is not None else 0

    p_stacks = int(_get_first(poison_stacks))
    hp = int(_get_first(enemy_hp))

    if p_stacks <= 0:
        return {
            "lethal_this_turn": False, 
            "turns_to_lethal": -1, 
            "total_poison_damage_possible": 0,
            "surviving_hp": hp
        }

    turns = 0
    total_dmg = 0
    current_p = p_stacks
    current_hp = hp

    while current_hp > 0 and current_p > 0:
        current_hp -= current_p
        total_dmg += current_p
        turns += 1
        current_p -= 1

    return {
        "lethal_this_turn": turns == 1,
        "turns_to_lethal": turns if current_hp <= 0 else -1,
        "total_poison_damage_possible": total_dmg,
        "surviving_hp": max(0, current_hp)
    }

