SCHEMA = {
    "name": "calc_lethal_shivs",
    "description": "Calculates the number of Shivs needed to kill an enemy, given Shiv damage, Enemy HP, Vulnerable, etc.",
    "input_schema": {
        "type": "object",
        "properties": {
            "enemy_hp": {"type": "integer"},
            "shiv_damage": {"type": "integer"},
            "enemy_vulnerable": {"type": "boolean"},
            "enemy_block": {"type": "integer"}
        },
        "required": ["enemy_hp", "shiv_damage"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(enemy_hp, shiv_damage, enemy_vulnerable=False, enemy_block=0):
    effective_damage = int(shiv_damage * 1.5) if enemy_vulnerable else shiv_damage
    total_effective_hp = enemy_hp + enemy_block
    if effective_damage <= 0:
        return {"shivs_needed": 999, "possible": False}
    import math
    shivs = math.ceil(total_effective_hp / effective_damage)
    return {"shivs_needed": shivs, "effective_damage": effective_damage, "possible": True}

