SCHEMA = {
    "name": "damage_survival_calculator",
    "description": "Calculates net damage and whether the player survives the incoming damage. Helps optimize HP efficiency by checking if the planned block is sufficient.",
    "input_schema": {
        "type": "object",
        "properties": {
            "current_hp": {"type": "integer"},
            "incoming_damage": {"type": "integer"},
            "current_block": {"type": "integer"},
            "planned_block": {"type": "integer"}
        },
        "required": ["current_hp", "incoming_damage", "current_block"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(current_hp, incoming_damage, current_block, planned_block=0):
    total_block = current_block + planned_block
    net_damage = max(0, incoming_damage - total_block)
    survives = current_hp > net_damage
    return {
        "net_damage": net_damage,
        "survives": survives,
        "hp_remaining": current_hp - net_damage if survives else 0
    }

